```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>
#include <variant>

#include "eas_common.hpp"

using namespace sqlgen;
using namespace sqlgen::literals;

// Helper: map from table name to a tag type used for dispatching.
struct StudentTag {};
struct CourseTag {};
struct ScoreTag {};
struct MajorTag {};

inline auto resolve_table_tag(const std::string& table_name) {
  if (table_name == "Student") return std::variant<StudentTag, CourseTag, ScoreTag, MajorTag>{StudentTag{}};
  if (table_name == "Course")  return std::variant<StudentTag, CourseTag, ScoreTag, MajorTag>{CourseTag{}};
  if (table_name == "Score")   return std::variant<StudentTag, CourseTag, ScoreTag, MajorTag>{ScoreTag{}};
  if (table_name == "Major")   return std::variant<StudentTag, CourseTag, ScoreTag, MajorTag>{MajorTag{}};
  throw std::runtime_error("Unknown table name: " + table_name);
}

// Generic add function – template parameter T must be the corresponding record struct
template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to DB
  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("Failed to connect to database: " +
                             conn_res.error().message());
  }
  auto& conn = conn_res.value();

  // Validate that T matches the table_name to avoid mismatched usage.
  // This is a runtime check; the intended use is:
  //   add_eas_records<Student>("Student", ...)
  //   add_eas_records<Course>("Course", ...)
  //   etc.
  auto tag = resolve_table_tag(table_name);
  bool type_ok = std::visit(
      [](auto t) -> bool {
        using Tag = decltype(t);
        if constexpr (std::is_same_v<Tag, StudentTag>)
          return std::is_same_v<T, Student>;
        else if constexpr (std::is_same_v<Tag, CourseTag>)
          return std::is_same_v<T, Course>;
        else if constexpr (std::is_same_v<Tag, ScoreTag>)
          return std::is_same_v<T, Score>;
        else if constexpr (std::is_same_v<Tag, MajorTag>)
          return std::is_same_v<T, Major>;
        else
          return false;
      },
      tag);

  if (!type_ok) {
    throw std::runtime_error(
        "Type of records does not match table '" + table_name + "'");
  }

  // Insert all records
  for (const auto& rec : records) {
    auto res = sqlgen::insert(rec)(conn);
    if (!res) {
      throw std::runtime_error("Failed to insert into " + table_name +
                               ": " + res.error().message());
    }
  }
}

// Modify a single column of a row by primary key.
// record_id is passed as string to be generic; it will be converted to the
// appropriate type depending on the table.
inline void modify_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id,
                                     const std::string& col_name,
                                     const std::string& new_value_json) {
  // new_value_json is assumed to be a JSON-encoded value (e.g. "42", "\"John\"")
  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("Failed to connect to database: " +
                             conn_res.error().message());
  }
  auto& conn = conn_res.value();

  auto tag = resolve_table_tag(table_name);

  std::visit(
      [&](auto t) {
        using Tag = decltype(t);
        if constexpr (std::is_same_v<Tag, StudentTag>) {
          using PK = typename rfl::field_type_t<decltype(&Student::SNo)>::value_type;
          PK pk_value = rfl::json::read<PK>(record_id);
          // Load existing row
          auto row_res = sqlgen::get<Student>(pk_value)(conn);
          if (!row_res) {
            throw std::runtime_error("Failed to load Student with SNo=" + record_id +
                                     ": " + row_res.error().message());
          }
          auto row = row_res.value();

          // Update field by name using rfl
          rfl::visit_fields(row, [&](auto& field, const char* name) {
            if (col_name == name) {
              using FieldType = std::decay_t<decltype(field)>;
              field = rfl::json::read<FieldType>(new_value_json);
            }
          });

          auto upd_res = sqlgen::update(row)(conn);
          if (!upd_res) {
            throw std::runtime_error("Failed to update Student: " +
                                     upd_res.error().message());
          }
        } else if constexpr (std::is_same_v<Tag, CourseTag>) {
          using PK = typename rfl::field_type_t<decltype(&Course::CID)>::value_type;
          PK pk_value = rfl::json::read<PK>(record_id);

          auto row_res = sqlgen::get<Course>(pk_value)(conn);
          if (!row_res) {
            throw std::runtime_error("Failed to load Course with CID=" + record_id +
                                     ": " + row_res.error().message());
          }
          auto row = row_res.value();

          rfl::visit_fields(row, [&](auto& field, const char* name) {
            if (col_name == name) {
              using FieldType = std::decay_t<decltype(field)>;
              field = rfl::json::read<FieldType>(new_value_json);
            }
          });

          auto upd_res = sqlgen::update(row)(conn);
          if (!upd_res) {
            throw std::runtime_error("Failed to update Course: " +
                                     upd_res.error().message());
          }
        } else if constexpr (std::is_same_v<Tag, ScoreTag>) {
          using PK = typename rfl::field_type_t<decltype(&Score::ScID)>::value_type;
          PK pk_value = rfl::json::read<PK>(record_id);

          auto row_res = sqlgen::get<Score>(pk_value)(conn);
          if (!row_res) {
            throw std::runtime_error("Failed to load Score with ScID=" + record_id +
                                     ": " + row_res.error().message());
          }
          auto row = row_res.value();

          rfl::visit_fields(row, [&](auto& field, const char* name) {
            if (col_name == name) {
              using FieldType = std::decay_t<decltype(field)>;
              field = rfl::json::read<FieldType>(new_value_json);
            }
          });

          auto upd_res = sqlgen::update(row)(conn);
          if (!upd_res) {
            throw std::runtime_error("Failed to update Score: " +
                                     upd_res.error().message());
          }
        } else if constexpr (std::is_same_v<Tag, MajorTag>) {
          using PK = typename rfl::field_type_t<decltype(&Major::MID)>::value_type;
          PK pk_value = rfl::json::read<PK>(record_id);

          auto row_res = sqlgen::get<Major>(pk_value)(conn);
          if (!row_res) {
            throw std::runtime_error("Failed to load Major with MID=" + record_id +
                                     ": " + row_res.error().message());
          }
          auto row = row_res.value();

          rfl::visit_fields(row, [&](auto& field, const char* name) {
            if (col_name == name) {
              using FieldType = std::decay_t<decltype(field)>;
              field = rfl::json::read<FieldType>(new_value_json);
            }
          });

          auto upd_res = sqlgen::update(row)(conn);
          if (!upd_res) {
            throw std::runtime_error("Failed to update Major: " +
                                     upd_res.error().message());
          }
        }
      },
      tag);
}

// Delete record by primary key.
// record_id is passed as string; we convert it to the correct primary-key type
// depending on table_name.
inline void delete_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id) {
  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("Failed to connect to database: " +
                             conn_res.error().message());
  }
  auto& conn = conn_res.value();

  auto tag = resolve_table_tag(table_name);

  std::visit(
      [&](auto t) {
        using Tag = decltype(t);
        if constexpr (std::is_same_v<Tag, StudentTag>) {
          using PK = typename rfl::field_type_t<decltype(&Student::SNo)>::value_type;
          PK pk_value = rfl::json::read<PK>(record_id);
          auto del_res = sqlgen::erase<Student>(pk_value)(conn);
          if (!del_res) {
            throw std::runtime_error("Failed to delete from Student: " +
                                     del_res.error().message());
          }
        } else if constexpr (std::is_same_v<Tag, CourseTag>) {
          using PK = typename rfl::field_type_t<decltype(&Course::CID)>::value_type;
          PK pk_value = rfl::json::read<PK>(record_id);
          auto del_res = sqlgen::erase<Course>(pk_value)(conn);
          if (!del_res) {
            throw std::runtime_error("Failed to delete from Course: " +
                                     del_res.error().message());
          }
        } else if constexpr (std::is_same_v<Tag, ScoreTag>) {
          using PK = typename rfl::field_type_t<decltype(&Score::ScID)>::value_type;
          PK pk_value = rfl::json::read<PK>(record_id);
          auto del_res = sqlgen::erase<Score>(pk_value)(conn);
          if (!del_res) {
            throw std::runtime_error("Failed to delete from Score: " +
                                     del_res.error().message());
          }
        } else if constexpr (std::is_same_v<Tag, MajorTag>) {
          using PK = typename rfl::field_type_t<decltype(&Major::MID)>::value_type;
          PK pk_value = rfl::json::read<PK>(record_id);
          auto del_res = sqlgen::erase<Major>(pk_value)(conn);
          if (!del_res) {
            throw std::runtime_error("Failed to delete from Major: " +
                                     del_res.error().message());
          }
        }
      },
      tag);
}
