          return std::is_same_v<T, Student>;
        else if constexpr (std::is_same_v<Tag, CourseTag>)
          return std::is_same_v<T, Course>;
        else if constexpr (std::is_same_v<Tag, ScoreTag>)
          return std::is_same_v<T, Score>;
        else if constexpr (std::is_same_v<Tag, MajorTag>)
          return std::is_same_v<T, Major>;
        else
          return false;
      },
      tag);

  if (!type_ok) {
    throw std::runtime_error(
        "Type of records does not match table '" + table_name + "'");
  }

  // Insert all records
  for (const auto& rec : records) {
    auto res = sqlgen::insert(rec)(conn);
    if (!res) {
      throw std::runtime_error("Failed to insert into " + table_name +
                               ": " + res.error().message());
    }
  }
}

// Modify a single column of a row by primary key.
// record_id is passed as string to be generic; it will be converted to the
// appropriate type depending on the table.
inline void modify_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id,
                                     const std::string& col_name,
                                     const std::string& new_value_json) {
  // new_value_json is assumed to be a JSON-encoded value (e.g. "42", "\"John\"")
  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("Failed to connect to database: " +
                             conn_res.error().message());
