  auto& conn = conn_res.value();

  auto tag = resolve_table_tag(table_name);

  std::visit(
      [&](auto t) {
        using Tag = decltype(t);
        if constexpr (std::is_same_v<Tag, StudentTag>) {
          using PK = typename rfl::field_type_t<decltype(&Student::SNo)>::value_type;
          PK pk_value = rfl::json::read<PK>(record_id);
