namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
  try {
    // Connect to SQLite database "test_db.sqlite"
    sqlgen::sqlite::Database db{"test_db.sqlite"};

    // (Drop if exists and) create Product table
    db.execute(R"(DROP TABLE IF EXISTS Product;)");
    db.execute(R"(
      CREATE TABLE Product (
        product_id INTEGER PRIMARY KEY,
        name       TEXT NOT NULL,
        price      REAL NOT NULL,
        category   TEXT NOT NULL,
        stock      INTEGER NOT NULL DEFAULT 0
      );
    )");

    // Create a model bound to the Product struct
    auto model = sqlgen::make_model<Product>(db, "Product");

    // Begin transaction
    db.begin_transaction();

    // Efficient batch insertion using sqlgen model
    // sqlgen::insert can take a range / container of objects
    model.insert(products);

    // Commit transaction if all inserts succeed
    db.commit();

    return true;
  } catch (const std::exception&) {
    // Roll back on any failure; ignore any rollback error
    try {
      sqlgen::sqlite::Database db{"test_db.sqlite"};
      db.rollback();
    } catch (...) {
      // best-effort rollback
    }
    return false;
  }
}

}  // namespace batch_insert_products
