namespace test_design_eas_database {

  // Student table mapping
  //
  // | Field    | Type        | Constraints / Defaults | Description     |
  // |----------|-------------|------------------------|-----------------|
  // | SNo      | varchar(10) | NOT NULL PRIMARY KEY   | Student ID (PK) |
  // | SName    | varchar(30) | NOT NULL               | Name            |
  // | Sex      | int         | NULL DEFAULT 1         | Gender          |
  // | Birthday | datetime    | NULL                   | Date of birth   |
  // | Major    | int         | NULL                   | Major           |
  // | Scorses  | float       | NULL DEFAULT 0         | Score           |
  // | Remark   | text        | NULL                   | Remarks         |
  struct Student {
    // Map to VARCHAR(10) PRIMARY KEY
    std::string SNo;
    // Map to VARCHAR(30) NOT NULL
    std::string SName;
    // Map to INTEGER NULL DEFAULT 1
    //
    // Using std::optional so "absence" can be represented;
    // DEFAULT 1 will be handled in the DDL.
    std::optional<int> Sex;
    // Map to DATETIME NULL
    // Represented as ISO-8601 string (TEXT) in SQLite.
    std::optional<std::string> Birthday;
    // Map to INTEGER NULL
    std::optional<int> Major;
    // Map to REAL NULL DEFAULT 0
    std::optional<double> Scorses;
    // Map to TEXT NULL
    std::optional<std::string> Remark;

    // rfl reflection macro so sqlgen can see the fields
    RFL_FIELDS(SNo, SName, Sex, Birthday, Major, Scorses, Remark);
  };

  // Course table mapping
  //
  // | Field  | Type        | Constraints / Defaults       | Description     |
  // |--------|-------------|------------------------------|-----------------|
  // | CID    | int         | NOT NULL auto_increment PK   | Course ID (PK)  |
  // | CName  | varchar(30) | NOT NULL                     | Course name     |
  // | Term   | int         | NULL DEFAULT 1               | Term            |
  // | CTime  | int         | NULL                         | Credit hours    |
  // | Credit | float       | NOT NULL DEFAULT 0           | Credits         |
  struct Course {
    // INTEGER PRIMARY KEY AUTOINCREMENT
    int CID;
    // VARCHAR(30) NOT NULL
    std::string CName;
    // INTEGER NULL DEFAULT 1
    std::optional<int> Term;
    // INTEGER NULL
    std::optional<int> CTime;
    // REAL NOT NULL DEFAULT 0
    double Credit;

    RFL_FIELDS(CID, CName, Term, CTime, Credit);
  };

  // Score table mapping
  //
  // | Field   | Type        | Constraints / Defaults                          |
  // |---------|-------------|-------------------------------------------------|
  // | SNo     | varchar(10) | NOT NULL                                       |
  // | CID     | int         | NOT NULL                                       |
  // | Score   | float       | NULL                                           |
  // | PK      | (SNo, CID)  | PRIMARY KEY(SNo, CID)                          |
  // | FK 1    | SNo         | FOREIGN KEY (SNo) REFERENCES Student(SNo)      |
  // | FK 2    | CID         | FOREIGN KEY (CID) REFERENCES Course(CID)       |
  struct Score {
    std::string SNo;
    int CID;
    std::optional<double> ScoreValue;

    RFL_FIELDS(SNo, CID, ScoreValue);
  };

  inline void design_eas_database() {
    using namespace sqlgen;
    using namespace sqlgen::sqlite;

    // Open / create SQLite database
    sqlite::connection conn{"test_db.sqlite"};

    // Enable foreign key constraints
    conn.execute("PRAGMA foreign_keys = ON;");

    // --- Define table schemas using sqlgen metadata ---

    // Student table
    auto student_table = make_table<Student>(
      "Student",
      make_column("SNo", &Student::SNo,
                  column_options::primary_key(),
                  column_options::not_null(),
                  column_options::type("VARCHAR(10)")),
      make_column("SName", &Student::SName,
                  column_options::not_null(),
                  column_options::type("VARCHAR(30)")),
      make_column("Sex", &Student::Sex,
                  column_options::default_value("1"),
                  column_options::type("INTEGER")),
      make_column("Birthday", &Student::Birthday,
                  column_options::type("DATETIME")),
      make_column("Major", &Student::Major,
                  column_options::type("INTEGER")),
      make_column("Scorses", &Student::Scorses,
                  column_options::default_value("0"),
                  column_options::type("REAL")),
      make_column("Remark", &Student::Remark,
                  column_options::type("TEXT"))
    );

    // Course table
    auto course_table = make_table<Course>(
      "Course",
      make_column("CID", &Course::CID,
                  column_options::primary_key(),
                  // In SQLite, INTEGER PRIMARY KEY is auto-incrementing
                  column_options::type("INTEGER")),
      make_column("CName", &Course::CName,
                  column_options::not_null(),
                  column_options::type("VARCHAR(30)")),
      make_column("Term", &Course::Term,
                  column_options::default_value("1"),
                  column_options::type("INTEGER")),
      make_column("CTime", &Course::CTime,
                  column_options::type("INTEGER")),
      make_column("Credit", &Course::Credit,
                  column_options::not_null(),
                  column_options::default_value("0"),
                  column_options::type("REAL"))
    );

    // Score table
    auto score_table = make_table<Score>(
      "Score",
      make_column("SNo", &Score::SNo,
                  column_options::not_null(),
                  column_options::type("VARCHAR(10)")),
      make_column("CID", &Score::CID,
                  column_options::not_null(),
                  column_options::type("INTEGER")),
      make_column("Score", &Score::ScoreValue,
                  column_options::type("REAL")),
      table_options::primary_key("SNo", "CID"),
      table_options::foreign_key({"SNo"}, "Student", {"SNo"}),
      table_options::foreign_key({"CID"}, "Course", {"CID"})
    );

    // --- Create tables in the database ---

    // Drop existing tables to get a clean schema (optional, but
    // helps to ensure idempotent design in a test context)
    conn.execute("DROP TABLE IF EXISTS Score;");
    conn.execute("DROP TABLE IF EXISTS Course;");
    conn.execute("DROP TABLE IF EXISTS Student;");

    // Create Student and Course first (parents of foreign keys)
    conn.execute(generate_create_table_sql(student_table));
    conn.execute(generate_create_table_sql(course_table));
    // Then create Score (which references them)
    conn.execute(generate_create_table_sql(score_table));
