#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_course_enrollment_stats {

struct Course {
  sqlgen::PrimaryKey<int> course_id;
  std::string title;
};

struct Enrollment {
  sqlgen::PrimaryKey<int> enrollment_id;
  sqlgen::ForeignKey<int, Course, "course_id"> course_id;
  std::optional<float> grade;
};

struct CourseStats {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

struct CourseStatsView {
  // View to store course enrollment statistics
  std::string title;
  int student_count;
  std::optional<double> avg_grade;

  // Map to our desired result type
  CourseStats to_course_stats() const {
    return CourseStats{title, student_count, avg_grade};
  }
};

/**
 * Function: Calculate enrollment statistics per course.
 *
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  // Open / create SQLite database
  sqlgen::sqlite::Database db("test_db.sqlite");

  // Create tables (if not exist)
  db.create_table<Course>();
  db.create_table<Enrollment>();

  // Register the view struct (needed for select)
  db.register_view<CourseStatsView>(
      "CourseStatsView",
      {
          {"title", &CourseStatsView::title},
          {"student_count", &CourseStatsView::student_count},
          {"avg_grade", &CourseStatsView::avg_grade},
      });

  // Build and execute the query:
  // SELECT c.title,
  //        COUNT(e.enrollment_id) AS student_count,
  //        AVG(e.grade)          AS avg_grade
  // FROM   Course c
  // LEFT JOIN Enrollment e ON c.course_id = e.course_id
  // GROUP BY c.course_id, c.title;

  sqlgen::Query<CourseStatsView> query;

  auto c = sqlgen::table<Course>("c");
  auto e = sqlgen::table<Enrollment>("e");

  query.select(
           c.title.as("title"),
           sqlgen::count(e.enrollment_id).as("student_count"),
           sqlgen::avg(e.grade).as("avg_grade"))
      .from(c)
      .left_join(e, c.course_id == e.course_id)
      .group_by(c.course_id, c.title);

  auto results = db.execute(query);

  std::vector<CourseStats> stats;
  stats.reserve(results.size());
  for (const auto &row : results) {
    stats.push_back(row.to_course_stats());
  }

  return stats;
}

}  // namespace query_course_enrollment_stats
