std::vector<PurchaseHistory> query_customer_purchase_history(int customer_id) {
  using namespace sqlgen;

  // 1. Connect to the SQLite database "test_db.sqlite"
  sqlite::Connection conn{"test_db.sqlite"};

  // 2. Create Customer, Order, OrderItem, Product tables
  {
    Schema schema{conn};
    schema.create_table_if_not_exists<Customer>();
    schema.create_table_if_not_exists<Product>();
    schema.create_table_if_not_exists<Order>();
    schema.create_table_if_not_exists<OrderItem>();
  }

