  // 4. Read and return the results as a vector of PurchaseHistory
  std::vector<PurchaseHistory> result;

  // Build and execute the query using a raw SQL statement mapped to PurchaseHistory
  auto stmt = conn.prepare(
      "SELECT p.name AS product_name, "
      "       o.order_date AS order_date, "
      "       oi.quantity AS quantity "
      "FROM Customer c "
      "JOIN \"Order\" o ON c.customer_id = o.customer_id "
      "JOIN OrderItem oi ON o.order_id = oi.order_id "
      "JOIN Product p ON oi.product_id = p.product_id "
      "WHERE c.customer_id = ? "
      "ORDER BY o.order_date DESC;"
  );

  stmt.bind(1, customer_id);

  while (stmt.step()) {
    PurchaseHistory ph;
    // Column indices: 0 = product_name, 1 = order_date, 2 = quantity
    ph.product_name = stmt.get<std::string>(0);
    ph.order_date = stmt.get<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">>(1);
    ph.quantity = stmt.get<int>(2);
    result.push_back(std::move(ph));
  }

  return result;
}

}  // namespace query_customer_purchase_history
