                         &Document::title,      "title",
                         &Document::is_deleted, "is_deleted",
                         &Document::deleted_at, "deleted_at");

    sqlgen::Database db{conn, schema};

    // Start a transaction so either all updates succeed or none do
    auto tx = db.transaction();

    // Build and execute:
