namespace update_eas_table {

void update_eas_table() {
  // Ensure the initial schema (including Major) exists.
  design_eas_database_with_major();

  // Connect to the database and apply the required schema changes.
  sqlgen::sqlite::connect(db_path)
      .and_then([](auto&& conn) {
        // 1. Add a new non-null char(1) column Grade to Score with a default.
        //    Using DEFAULT 'F' so existing rows satisfy NOT NULL.
        return sqlgen::exec(
            conn,
            "ALTER TABLE Score "
            "ADD COLUMN Grade CHAR(1) NOT NULL DEFAULT 'F';");
      })
      .and_then([](auto&& conn) {
        // 2. Modify Student.Age to INT NULL.
        // SQLite doesn't support ALTER COLUMN directly, so we
        // recreate the Student table with the desired schema.
        //
        // Assumed existing Student schema:
        //   Student(SNo, Name, Sex, Birthday, Major, Scores, Remark, Age)
        //
        // We:
        //   - create a new table Student_new with Age INT NULL
        //   - copy data over
        //   - drop old table
        //   - rename Student_new to Student

        // Create new Student table.
        auto res = sqlgen::exec(
            conn,
            "CREATE TABLE IF NOT EXISTS Student_new ("
            "  SNo      VARCHAR(10) PRIMARY KEY,"
            "  Name     VARCHAR(30) NOT NULL,"
            "  Sex      INTEGER NOT NULL,"
            "  Birthday TEXT,"
            "  Major    INTEGER,"
            "  Scores   REAL,"
            "  Remark   TEXT,"
            "  Age      INTEGER"
            ");");
        if (!res) return res;

        // Copy data from old Student; Age will be NULL if it existed but
        // with incompatible type, or absent.
        res = sqlgen::exec(
            conn,
            "INSERT INTO Student_new (SNo, Name, Sex, Birthday, Major, Scores, Remark, Age) "
            "SELECT SNo, Name, Sex, Birthday, Major, Scores, Remark, Age "
            "FROM Student;");
        if (!res) return res;

        // Drop old Student table.
        res = sqlgen::exec(conn, "DROP TABLE Student;");
        if (!res) return res;

        // Rename new table.
        return sqlgen::exec(conn, "ALTER TABLE Student_new RENAME TO Student;");
      })
      .and_then([](auto&& conn) {
        // 3. Drop the Major table.
        return sqlgen::exec(conn, "DROP TABLE IF EXISTS Major;");
      })
      .value();
}

} // namespace update_eas_table
