bool create_view_sales_summary() {
  try {
    // 1. Open SQLite connection to test_db.sqlite
    sqlgen::sqlite::connection conn{"test_db.sqlite"};

    // 2. Manually DROP VIEW IF EXISTS (SQLite has this syntax for views)
    {
      auto drop_stmt = conn.prepare("DROP VIEW IF EXISTS SalesSummary;");
      drop_stmt.execute();
