namespace right_join_departments_projects {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string name;
};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;

  // Connect to SQLite database "test_db.sqlite"
  sqlite::Database db("test_db.sqlite");

  // Create a store for Department and Project models
  Store<sqlite::Database, Department, Project> store(db);

  // NOTE:
  // SQLite does not natively support RIGHT JOIN, and sqlgen mirrors that.
  // To demonstrate "include all departments (even without projects)"
  // we perform a LEFT JOIN from Department to Project, which is
  // semantically equivalent to a RIGHT JOIN from Project to Department.
  //
  // LEFT JOIN Department -> Project == RIGHT JOIN Project -> Department

  // Build a read query that left-joins Project on Department
  auto query =
      store.read<Department, Project>()
          .leftJoin<Project>(on(&Department::department_id, &Project::department_id));

  std::vector<DepProj> result;

  // Execute the query and transform rows into DepProj
  query.forEachRow(
      [&](const Department* dept, const Project* proj) {
        DepProj dp;

        // Department is always present in a LEFT JOIN root
        if (dept) {
          dp.department_name = dept->name;
        } else {
          dp.department_name = std::nullopt;
        }

        // For departments without projects, Project pointer will be nullptr.
        // The function specification requires inclusion of departments
        // without projects, but DepProj::project_name is a std::string,
        // so we keep it empty for such rows.
        if (proj) {
          dp.project_name = proj->name;
        } else {
          dp.project_name = "";
        }

        result.emplace_back(std::move(dp));
      });

  return result;
}

}  // namespace right_join_departments_projects
