std::string generate_sql_dry_run() {
  // 1. Prepare SQLite backend (no execution, just SQL generation)
  sqlgen::sqlite::Dialect sqlite_dialect;

  // 2. Build a complex query using sqlgen:
  //    SELECT A.id, A.name, B.score
  //    FROM A
  //    JOIN B ON A.id = B.a_id
  //    WHERE B.score > 10 AND A.name LIKE '%x%'
  //    ORDER BY B.score DESC, A.name ASC
  //    LIMIT 50;
  auto q = sqlgen::select(&A::id, &A::name, &B::score)
               .from<A>()
               .join<B>(sqlgen::on(&A::id == &B::a_id))
               .where((&B::score > 10.0) &&
                      (&A::name.like("%x%")))
               .order_by(&B::score.desc(), &A::name.asc())
               .limit(50);

  // 3. Generate SQL string for SQLite (dry run)
  std::string sql = sqlgen::to_sql(q, sqlite_dialect);

  // 4. Basic verification the generated SQL contains expected clauses
  //    (for debugging / sanity check)
  auto contains = [&](const std::string& needle) {
    return sql.find(needle) != std::string::npos;
  };

  if (!contains("FROM A") && !contains("from A") && !contains("FROM \"A\""))
    throw std::runtime_error("Generated SQL missing FROM A clause");

  if (!contains("JOIN B") && !contains("join B") && !contains("JOIN \"B\""))
    throw std::runtime_error("Generated SQL missing JOIN B clause");

  if (!contains("WHERE") && !contains("where"))
    throw std::runtime_error("Generated SQL missing WHERE clause");

  if (!contains("ORDER BY") && !contains("order by"))
    throw std::runtime_error("Generated SQL missing ORDER BY clause");

  if (!contains("LIMIT 50") && !contains("limit 50"))
    throw std::runtime_error("Generated SQL missing LIMIT 50 clause");

  // 5. Return the generated SQL string (no execution performed)
  return sql;
}

