/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Inserts the provided events into a SQLite database, runs a query
 * to extract date/time parts and compute duration, and returns the results
 * as a vector of TemporalAnalysis.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data(const std::vector<Event>& events) {
  using namespace sqlgen;

  // Connect to the required SQLite database file.
  sqlite::Connection conn("test_db.sqlite");

  // Make sure the Event table exists with the expected schema.
  {
    auto ddl = R"SQL(
      CREATE TABLE IF NOT EXISTS Event (
        event_id    INTEGER PRIMARY KEY,
        event_name  TEXT NOT NULL,
        start_time  TEXT NOT NULL,
        end_time    TEXT,
        created_at  TEXT NOT NULL
      );
    )SQL";
    conn.execute(ddl);
  }

  // Prepare ORM model for Event.
  auto event_model = make_model<Event>("Event",
                                       &Event::event_id,
                                       &Event::event_name,
                                       &Event::start_time,
                                       &Event::end_time,
                                       &Event::created_at);

  // For simplicity, clear existing rows so this function reflects exactly
  // the provided set of events.
  {
    auto clear_stmt = conn.prepare("DELETE FROM Event;");
    clear_stmt.execute();
  }

  // Insert all provided events.
  {
    auto inserter = sqlite::make_inserter(conn, event_model);
    for (const auto& e : events) {
      inserter.insert(e);
    }
  }

  // We now run a query that matches the reference SQL, using SQLite
  // date/time functions to approximate the requested operations.
  //
  // - DAY(start_time)     -> CAST(STRFTIME('%d', start_time) AS INTEGER)
  // - MONTH(start_time)   -> CAST(STRFTIME('%m', start_time) AS INTEGER)
  // - YEAR(start_time)    -> CAST(STRFTIME('%Y', start_time) AS INTEGER)
  // - HOUR(start_time)    -> CAST(STRFTIME('%H', start_time) AS INTEGER)
  // - MINUTE(start_time)  -> CAST(STRFTIME('%M', start_time) AS INTEGER)
  // - SECOND(start_time)  -> CAST(STRFTIME('%S', start_time) AS INTEGER)
  // - WEEKDAY(start_time) -> CAST(STRFTIME('%w', start_time) AS INTEGER)
  //                          (0=Sunday..6=Saturday; if Monday=0 is desired,
  //                           you can adjust as (strftime('%w') + 6) % 7)
  // - UNIXEPOCH(start_time) -> CAST(STRFTIME('%s', start_time) AS INTEGER)
  // - DAYS_BETWEEN(start_time, end_time)
  //     -> (JULIANDAY(end_time) - JULIANDAY(start_time))
  //
  // Only rows with non-null end_time participate (as in the WHERE clause).
  auto query_sql = R"SQL(
    SELECT
      event_id,
      event_name,
      CAST(STRFTIME('%d', start_time) AS INTEGER) AS start_day,
      CAST(STRFTIME('%m', start_time) AS INTEGER) AS start_month,
      CAST(STRFTIME('%Y', start_time) AS INTEGER) AS start_year,
      CAST(STRFTIME('%H', start_time) AS INTEGER) AS start_hour,
      CAST(STRFTIME('%M', start_time) AS INTEGER) AS start_minute,
      CAST(STRFTIME('%S', start_time) AS INTEGER) AS start_second,
      CAST(STRFTIME('%w', start_time) AS INTEGER) AS start_weekday,
      CAST(STRFTIME('%s', start_time) AS INTEGER) AS start_epoch,
      (JULIANDAY(end_time) - JULIANDAY(start_time)) AS duration_days
    FROM Event
    WHERE end_time IS NOT NULL;
  )SQL";

  auto stmt = conn.prepare(query_sql);

  std::vector<TemporalAnalysis> results;
  while (stmt.step()) {
    TemporalAnalysis ta;

    // Column order must match SELECT list above.
    ta.event_id      = stmt.column_int(0);
    ta.event_name    = stmt.column_text(1);
    ta.start_day     = stmt.column_int(2);
    ta.start_month   = stmt.column_int(3);
    ta.start_year    = stmt.column_int(4);
    ta.start_hour    = stmt.column_int(5);
    ta.start_minute  = stmt.column_int(6);
    ta.start_second  = stmt.column_int(7);
    ta.start_weekday = stmt.column_int(8);
    ta.start_epoch   = static_cast<int64_t>(stmt.column_int64(9));

    if (stmt.column_type(10) == SQLITE_NULL) {
      ta.duration_days = std::nullopt;
    } else {
      ta.duration_days = stmt.column_double(10);
    }

    results.push_back(std::move(ta));
  }

  return results;
}

}  // namespace analyze_temporal_data
```

