  {
    const char* sql_most_connected = R"SQL(
      WITH friend_counts AS (
        SELECT u.user_id,
               u.username,
               COUNT(DISTINCT CASE
                 WHEN f.user_id1 = u.user_id THEN f.user_id2
                 WHEN f.user_id2 = u.user_id THEN f.user_id1
               END) AS friend_count
        FROM User u
        LEFT JOIN Friendship f
          ON (f.user_id1 = u.user_id OR f.user_id2 = u.user_id)
        GROUP BY u.user_id, u.username
      )
      SELECT user_id, username, friend_count
      FROM friend_counts
      WHERE friend_count = (
        SELECT MAX(friend_count) FROM friend_counts
      );
    )SQL";

    auto stmt = conn.prepare(sql_most_connected);
    while (stmt.step()) {
      // Demonstration: most connected users
      (void)stmt.column_int(0);   // user_id
      (void)stmt.column_text(1);  // username
      (void)stmt.column_int(2);   // friend_count
    }
  }

