      JOIN User u2
        ON u1.city = u2.city
       AND u1.user_id < u2.user_id
      WHERE NOT EXISTS (
        SELECT 1
        FROM Friendship f
        WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
           OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
      );
    )SQL";

    auto stmt = conn.prepare(sql_same_city_not_friends);
    while (stmt.step()) {
      // Demonstration only; not added to result
      (void)stmt.column_text(0); // user1_name
      (void)stmt.column_text(1); // user2_name
      (void)stmt.column_text(2); // city
    }
  }

  // Return mutual friend connections (from 4.1)
  return result;
}

}  // namespace analyze_social_network
