          JOIN Friendship mf2 ON mf.user_id2 = mf2.user_id2
          WHERE mf.user_id1 = u1.user_id
            AND mf2.user_id1 = u3.user_id
        ) = 1;
    )SQL";

    auto stmt = conn.prepare(sql_friend_of_friend);
    while (stmt.step()) {
      // Demonstration only; not added to result
      (void)stmt.column_text(0);
      (void)stmt.column_text(1);
    }
  }

  // 4.4 Count friends per user and identify most connected users
  {
    const char* sql_most_connected = R"SQL(
      WITH friend_counts AS (
        SELECT u.user_id,
               u.username,
               COUNT(DISTINCT CASE
                 WHEN f.user_id1 = u.user_id THEN f.user_id2
                 WHEN f.user_id2 = u.user_id THEN f.user_id1
               END) AS friend_count
        FROM User u
        LEFT JOIN Friendship f
          ON (f.user_id1 = u.user_id OR f.user_id2 = u.user_id)
        GROUP BY u.user_id, u.username
      )
      SELECT user_id, username, friend_count
      FROM friend_counts
      WHERE friend_count = (
        SELECT MAX(friend_count) FROM friend_counts
      );
    )SQL";

    auto stmt = conn.prepare(sql_most_connected);
    while (stmt.step()) {
      // Demonstration: most connected users
      (void)stmt.column_int(0);   // user_id
      (void)stmt.column_text(1);  // username
      (void)stmt.column_int(2);   // friend_count
    }
  }

  // 4.5 Recommendation: users in the same city who are not yet friends
  {
    const char* sql_same_city_not_friends = R"SQL(
      SELECT u1.username, u2.username, u1.city
      FROM User u1
      JOIN User u2
        ON u1.city = u2.city
       AND u1.user_id < u2.user_id
      WHERE NOT EXISTS (
        SELECT 1
        FROM Friendship f
        WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
           OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
      );
    )SQL";

    auto stmt = conn.prepare(sql_same_city_not_friends);
    while (stmt.step()) {
      // Demonstration only; not added to result
      (void)stmt.column_text(0); // user1_name
      (void)stmt.column_text(1); // user2_name
      (void)stmt.column_text(2); // city
    }
  }

  // Return mutual friend connections (from 4.1)
  return result;
}

