  sqlgen::sqlite::database db("test_db.sqlite");

  // Register the UserProfile table mapping
  sqlgen::table<UserProfile> user_profile_table("UserProfile",
                                                &UserProfile::user_id, "user_id",
                                                &UserProfile::name,    "name",
                                                &UserProfile::email,   "email");

  // We want to:
