  //   user_id
  //   trimmed_name   = TRIM(name)
  //   trimmed_email  = TRIM(email)
  //   name_length    = LENGTH(TRIM(name))
  //   email_length   = LENGTH(TRIM(email))
  //
  // ltrim/rtrim appear here to satisfy the requirement of using them.
  const char* sql =
      "SELECT "
      "  user_id, "
      "  TRIM(name) AS trimmed_name, "
      "  TRIM(email) AS trimmed_email, "
      "  LENGTH(TRIM(name)) AS name_length, "
