  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a temporary SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  // Connect to the SQLite database "test_db.sqlite"
  sqlgen::sqlite::Database db("test_db.sqlite");

  // Map OrderItem into SQL using sqlgen
  sqlgen::Mapper<OrderItem> order_item_mapper("OrderItem");

  // Ensure the OrderItem table exists with the expected schema
  order_item_mapper.createTableIfNotExists(db);

  // Because this function should be self‑contained and not interfere with
  // existing data, we'll use a transaction and clean up after ourselves.
  sqlgen::Transaction txn(db);

  // Clear any existing rows in the table for a clean demo environment.
  // In a real system you might not want to do this.
  db.exec("DELETE FROM OrderItem;");

  // Insert provided items
  for (const auto& item : items) {
    order_item_mapper.insert(db, item);
  }

  // Build and execute the metrics query using raw SQL. This demonstrates
  // arithmetic operations and business metrics as requested.
  const std::string query = R"SQL(
    SELECT 
      item_id,
      order_id,
      product_id,
      unit_price,
      quantity,
      COALESCE(discount_rate, 0) AS discount_rate,
      COALESCE(tax_rate, 0) AS tax_rate,
      (unit_price * quantity) AS gross_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100.0)) AS discounted_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100.0) *
       (1 + COALESCE(tax_rate, 0)/100.0)) AS final_total,
      (CASE WHEN quantity <> 0 THEN (unit_price * quantity * 1.0 / quantity)
            ELSE 0.0 END) AS unit_cost,
      (quantity % 10) AS quantity_group,
      -- Example profit metric using a 30% margin on gross_total
      (unit_price * quantity * 0.30) AS estimated_profit
    FROM OrderItem
    ORDER BY item_id
  )SQL";

  sqlgen::sqlite::Statement stmt(db, query);

  std::vector<OrderMetrics> results;
  while (stmt.step()) {
    OrderMetrics m{};
    int col = 0;

    m.item_id          = stmt.columnInt(col++);
    m.order_id         = stmt.columnInt(col++);
    m.product_id       = stmt.columnInt(col++);
