  sqlgen::PrimaryKey<int> note_id;
  std::string updated_content;
};

/**
 * description: replace_text_in_notes.
 * This function demonstrates how to replace text in notes using sqlgen update API.
 * It replaces all occurrences of "foo" with "bar" in the content column of the Note table.
 * Returns: std::vector<UpdatedNote>.
 */
std::vector<UpdatedNote> replace_text_in_notes() {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::connection conn{"test_db.sqlite"};

  // Create a schema object for the Notes table
  auto notes = make_table<Note>("Notes");

  // 1) Load all notes so we can process their content in C++
  auto all_notes = select(conn, notes).all();

  // 2) Do the string replacement and issue UPDATE statements
  //    This demonstrates sqlgen's update API. We update only rows whose
  //    content actually changes.
  for (auto &n : all_notes) {
    const std::string from = "foo";
    const std::string to   = "bar";

    // Replace all occurrences of "foo" with "bar" in n.content
    std::string updated = n.content;
    std::size_t pos = 0;
    bool changed = false;

    while ((pos = updated.find(from, pos)) != std::string::npos) {
      updated.replace(pos, from.size(), to);
      pos += to.size();
      changed = true;
    }

    if (changed) {
      // Use sqlgen's update API:
      // UPDATE Notes SET content = :updated WHERE note_id = :note_id;
      update(conn, notes)
          .set(&Note::content = updated)
          .where(&Note::note_id == n.note_id)
          .execute();

      // Keep our in-memory copy in sync for the final return
      n.content = updated;
    }
  }

  // 3) Build and return the updated view for verification
  std::vector<UpdatedNote> result;
  result.reserve(all_notes.size());
  for (const auto &n : all_notes) {
    result.push_back(UpdatedNote{n.note_id, n.content});
  }

  return result;
}

}  // namespace replace_text_in_notes
