bool inventory_bulk_write_and_read(const std::vector<Inventory>& items) {
  // Connect to SQLite database "test_db.sqlite"
  // The connection object manages the lifetime of the DB handle.
  sqlgen::sqlite::Connection conn{"test_db.sqlite"};

  // Define ORM mapping for Inventory table
  auto inventoryTable = sqlgen::make_table<Inventory>(
      "Inventory",
      &Inventory::item_id,  // PRIMARY KEY
      &Inventory::name,
      &Inventory::quantity,
      &Inventory::location);

  // 1) Drop and recreate the table to ensure a clean state.
  //    (If the table does not exist, DROP IF EXISTS is typically safe;
  //     create_table will create it with the fields mapped above.)
  conn.execute("DROP TABLE IF EXISTS Inventory;");
  conn.execute(inventoryTable.create_table_statement());

  // 2) Bulk insert the provided items.
  //    sqlgen provides a convenience function to insert a range.
  if (!items.empty()) {
    inventoryTable.insert_range(conn, items.begin(), items.end());
  }

  // 3) Read items where quantity > 50, ordered by quantity DESC.
  //    Build a SELECT query with WHERE and ORDER BY using sqlgen's query DSL.
  //    We select all columns into Inventory objects.
  auto q = inventoryTable.select()
               .where(inventoryTable.col(&Inventory::quantity) > 50)
               .order_by(inventoryTable.col(&Inventory::quantity), sqlgen::order::desc);

  std::vector<Inventory> result;
  inventoryTable.query(conn, q, std::back_inserter(result));

  // Return true if at least one qualifying item was found.
  return !result.empty();
