#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  using namespace sqlgen;

  // Open / create SQLite database
  sqlite::Database db("test_db.sqlite");

  // Ensure foreign key constraints are enforced
  db.execute("PRAGMA foreign_keys = ON;");

  // Create tables (dropping first for a clean demo)
  db.execute("DROP TABLE IF EXISTS Child;");
  db.execute("DROP TABLE IF EXISTS Parent;");

  // Generate CREATE TABLE statements from the C++ models
  auto parent_ddl = sqlite::make_table<Parent>("Parent");
  auto child_ddl  = sqlite::make_table<Child>("Child",
                      ForeignKey(&Child::parent_id)
                        .references<Parent>(&Parent::parent_id)
                        .on_delete_cascade());

  db.execute(parent_ddl);
  db.execute(child_ddl);

  // Insert a parent and two children sharing the same parent_id
  {
    sqlite::insert<Parent>(db, "Parent", Parent{1, "Parent A"});
    sqlite::insert<Child>(db, "Child", Child{1, 1, "Child 1 of Parent A"});
    sqlite::insert<Child>(db, "Child", Child{2, 1, "Child 2 of Parent A"});
  }

  // Delete the parent row
  db.execute("DELETE FROM Parent WHERE parent_id = 1;");

  // Verify whether child rows are deleted automatically
  int remaining_children = 0;
  {
    auto stmt = db.prepare("SELECT COUNT(*) FROM Child;");
    if (stmt.step()) {
      remaining_children = stmt.column_int(0);
    }
  }

  // Return true if cascade deletion removed all children
  return remaining_children == 0;
}

}  // namespace cascade_delete_demo
