#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace update_set_operations {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
  std::string status;
};

/**
 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  try {
    // Open SQLite database "test_db.sqlite"
    sqlgen::sqlite::Database db{"test_db.sqlite"};

    // Create/attach schema for Account table
    auto schema = sqlgen::make_schema<Account>("Account");

    // Get a write connection
    auto conn = db.connect(schema);

    // 1. Create Account table (if it doesn't exist)
    conn.create_table<Account>();

    // Clean up any previous data for a deterministic example
    conn.remove<Account>([](auto &) { return true; });

    // Insert some initial rows
    Account a1{1, 100.0, "active"};
    Account a2{2, 200.0, "inactive"};
    Account a3{3, 300.0, "active"};
    conn.insert(a1);
    conn.insert(a2);
    conn.insert(a3);

    // 2. Update balances and statuses using set(...)

    // Example 1: Give a 50-unit bonus to all active accounts,
    // and set their status to "bonus_applied"
    conn.update<Account>(
        [](auto &row) {
          row.set(row.balance = row.balance + 50.0,
                  row.status  = "bonus_applied");
        },
        [](auto &row) {
          return row.status == "active";
        });

    // Example 2: Deactivate accounts whose balance is below 200
    conn.update<Account>(
        [](auto &row) {
          row.set(row.status = "inactive");
        },
        [](auto &row) {
          return row.balance < 200.0;
        });

    // 3. Verify changes persisted by re-reading rows

    // Fetch all accounts
    auto accounts = conn.select<Account>();

    // We inserted 3 accounts; ensure we still have 3
    if (accounts.size() != 3) {
      return false;
    }

    // Build a small lookup by id
    Account acc1{}, acc2{}, acc3{};
    for (const auto &acc : accounts) {
      if (acc.account_id == 1) acc1 = acc;
      if (acc.account_id == 2) acc2 = acc;
      if (acc.account_id == 3) acc3 = acc;
    }

    // After updates:
    // a1: initial (100, "active")
    //  -> +50 bonus -> (150, "bonus_applied")
    //  -> balance < 200 => "inactive"
    //
    // a2: initial (200, "inactive")
