bool update_set_operations() {
  try {
    // Open SQLite database "test_db.sqlite"
    sqlgen::sqlite::Database db{"test_db.sqlite"};

    // Create/attach schema for Account table
    auto schema = sqlgen::make_schema<Account>("Account");

    // Get a write connection
    auto conn = db.connect(schema);

    // 1. Create Account table (if it doesn't exist)
    conn.create_table<Account>();

    // Clean up any previous data for a deterministic example
    conn.remove<Account>([](auto &) { return true; });

    // Insert some initial rows
    Account a1{1, 100.0, "active"};
    Account a2{2, 200.0, "inactive"};
    Account a3{3, 300.0, "active"};
    conn.insert(a1);
    conn.insert(a2);
