```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier
 * and the name of a product, if any.
 *
 * This demonstrates a FULL OUTER JOIN between Supplier and Product using SQLite,
 * which does not natively support FULL JOIN. We emulate FULL JOIN as:
 *
 *   (LEFT JOIN: all suppliers, products if present)
 *   UNION ALL
 *   (RIGHT-ONLY side: products with no matching supplier)
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // Open connection to SQLite database "test_db.sqlite"
  SqliteConnection conn("test_db.sqlite");

  // Make sure sqlgen knows the mappings (if not done elsewhere)
  conn.map<Supplier>("Supplier",
                     &Supplier::supplier_id, "supplier_id",
                     &Supplier::name,        "name");

  conn.map<Product>("Product",
                    &Product::product_id, "product_id",
                    &Product::supplier_id,"supplier_id",
                    &Product::name,       "name");

  // Because SQLite lacks FULL OUTER JOIN, emulate it with:
  //
  // 1) All suppliers, with matching products if any (LEFT JOIN)
  // 2) All products without any matching supplier (RIGHT-ONLY portion)
  //
  // Then UNION ALL the two result sets.
  //
  // We use aliased column names so we can read them consistently.
  const char* sql = R"SQL(
    SELECT
      s.name AS supplier_name,
      p.name AS product_name
    FROM Supplier s
    LEFT JOIN Product p
      ON s.supplier_id = p.supplier_id

    UNION ALL

    SELECT
      s2.name AS supplier_name,
      p2.name AS product_name
    FROM Product p2
    LEFT JOIN Supplier s2
      ON p2.supplier_id = s2.supplier_id
    WHERE s2.supplier_id IS NULL
  )SQL";

  std::vector<SupProd> results;

  Statement stmt(conn, sql);
  while (stmt.step()) {
    SupProd row;

    // supplier_name is always present in this emulation:
    //   - real supplier name for left-join part
    //   - NULL for right-only products (no supplier) -> treat as empty string
    if (!stmt.is_null(0)) {
      row.supplier_name = stmt.column_text(0);
    } else {
      row.supplier_name = "";
    }

    // product_name can be NULL (supplier without products)
    if (!stmt.is_null(1)) {
      row.product_name = stmt.column_text(1);
    } else {
      row.product_name = std::nullopt;
    }

    results.emplace_back(std::move(row));
  }

  return results;
}

}  // namespace full_join_suppliers_products
```

