JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts,
                                               const std::vector<Employee>& emps) {
  using sqlgen::sqlite::Database;

  // Connect to SQLite database "test_db.sqlite"
  Database db("test_db.sqlite");

  // Ensure tables exist (schema closely matches the description)
  db.execute(R"SQL(
    CREATE TABLE IF NOT EXISTS Department (
      department_id   INTEGER PRIMARY KEY,
      department_name TEXT NOT NULL,
      location        TEXT
    );
  )SQL");

  db.execute(R"SQL(
    CREATE TABLE IF NOT EXISTS Employee (
      employee_id   INTEGER PRIMARY KEY,
      department_id INTEGER,
      first_name    TEXT NOT NULL,
      last_name     TEXT NOT NULL,
      salary        REAL NOT NULL,
      FOREIGN KEY(department_id) REFERENCES Department(department_id)
    );
  )SQL");

  // Clear any existing data so the analysis reflects the provided vectors only
  db.execute("DELETE FROM Employee;");
  db.execute("DELETE FROM Department;");

  // Insert provided Department rows
  {
    auto inserter = sqlgen::make_inserter<Department>(db, "Department");
    for (const auto& d : depts) {
      inserter.insert(d);
    }
  }

  // Insert provided Employee rows
  {
    auto inserter = sqlgen::make_inserter<Employee>(db, "Employee");
    for (const auto& e : emps) {
      inserter.insert(e);
    }
  }

  JoinAnalysis analysis;

  // Helper lambda to run a join query and collect rows into a vector<JoinResult>
