  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Date sale_date;
};

struct TopProduct {
  int product_id;
  std::string product_name;
  std::string category;
  double total_sales;
};

/**
 * Description: This function retrieves the top products based on total sales.
 * Returns: std::vector<TopProduct>.
 */
std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  // Open SQLite database using sqlgen
  sqlgen::sqlite::Database db("test_db.sqlite");

  // Build the query using sqlgen's query builder
  auto query =
      sqlgen::select(
          Product{}.product_id,
          Product{}.product_name,
          Product{}.category,
          sqlgen::sum(Product{}.price * Sales{}.quantity).as("total_sales"))
          .from<Product>()
          .inner_join<Sales>(Product{}.product_id == Sales{}.product_id)
          .group_by(
              Product{}.product_id,
              Product{}.product_name,
              Product{}.category)
          .order_by(sqlgen::desc(sqlgen::column("total_sales")))
          .limit(static_cast<int>(limit_count));

  std::vector<TopProduct> results;

  // Execute the query and map results into TopProduct structures
  db.execute(query, [&](int product_id,
                        const std::string& product_name,
                        const std::string& category,
                        double total_sales) {
    TopProduct tp;
    tp.product_id = product_id;
    tp.product_name = product_name;
    tp.category = category;
    tp.total_sales = total_sales;
    results.push_back(std::move(tp));
  });

  return results;
}

