  db.execute(R"SQL(
    CREATE VIEW IF NOT EXISTS OrderSummaryView AS
    SELECT o.order_id,
           o.customer,
           SUM(oi.unit_price * oi.quantity) AS total
    FROM "Order" o
    INNER JOIN OrderItem oi
      ON o.order_id = oi.order_id
    GROUP BY o.order_id, o.customer;
  )SQL");

  // Read from the view to verify data
  auto results = db.select_from<OrderSummary>();

  // Return verification results
  return results;
}

