```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;         // 0 = Sunday, 1 = Monday, ..., 6 = Saturday (SQLite's strftime('%w'))
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  using namespace sqlgen;

  // Open connection to the SQLite database.
  sqlite::Database db("test_db.sqlite");

  // Create a query object bound to the Sales table.
  auto salesTable = make_table<Sales>("Sales");

  // We will use SQLite's strftime('%w', sale_time) to extract weekday:
  // '%w' => day of week 0-6 with 0 = Sunday.
  //
  // sqlgen allows raw SQL expressions via sqlgen::raw for computed fields.
  // We need:
  //   SELECT CAST(strftime('%w', sale_time) AS INTEGER) AS weekday,
  //          SUM(quantity) AS total_quantity
  //   FROM Sales
  //   GROUP BY weekday
  //
  // Then map the result into WeekdayStats.

  // Define a lightweight struct to map the aggregated query result.
  struct Row {
    int weekday;
    int total_quantity;
  };

  // Build the select with a raw expression for weekday.
  // Note: Depending on the exact sqlgen API, raw() may need a template type;
  // here we assume sqlgen::raw<int>(...) to indicate the result type.
  auto weekdayExpr =
      raw<int>("CAST(strftime('%w', sale_time) AS INTEGER)");

  auto query = db.select<Row>()
      .columns(weekdayExpr, sum(salesTable->quantity))
      .from(salesTable)
      .group_by(weekdayExpr);

  std::vector<Row> rows = query.execute();

  std::vector<WeekdayStats> result;
  result.reserve(rows.size());
  for (const auto& r : rows) {
    result.push_back(WeekdayStats{r.weekday, r.total_quantity});
  }

  return result;
}

}  // namespace weekday_sales_analysis
