/**
 * Description: This function tracks time metrics for each project, including day, month, year, hour, minute, second, and duration in days.
 * Returns: std::vector<TimeMetrics>.
 *
 * Notes:
 * - Connects to SQLite DB file "test_db.sqlite".
 * - Assumes tables "Project" and "TimeLog" exist with the given schema.
 * - Uses SQLite's strftime for date/time extraction and julianday for day differences.
 * - Computes per-log metrics and returns them as a flat list; callers can
 *   further aggregate/group by project and week as needed.
 */
std::vector<TimeMetrics> project_time_tracking() {
  using namespace sqlgen;

  // Open SQLite connection
  sqlite::connection conn{"test_db.sqlite"};

  // The reference SQL uses DAY/MONTH/YEAR/HOUR/MINUTE/SECOND/DAYS_BETWEEN which
  // are not native SQLite functions. Here we use SQLite equivalents:
  //
  //   DAY      -> strftime('%d', start_time)
  //   MONTH    -> strftime('%m', start_time)
  //   YEAR     -> strftime('%Y', start_time)
  //   HOUR     -> strftime('%H', start_time)
  //   MINUTE   -> strftime('%M', start_time)
  //   SECOND   -> strftime('%S', start_time)
  //   DAYS_BETWEEN(a,b) -> julianday(b) - julianday(a)
  //
  // For "weekly grouped metrics" we compute the ISO-like week year/week number
  // on the C++ side from the extracted date components.

  // Define a lightweight row type for raw query results
  struct RawRow {
    int project_id;
    std::string name;
    int day;
    int month;
    int year;
    int hour;
    int minute;
    int second;
    double duration_days;
  };

  // Prepare and execute the SQL query using sqlgen
  auto stmt = conn.prepare(
      "SELECT p.project_id, p.name, "
      "       CAST(strftime('%d', t.start_time) AS INTEGER) AS day, "
      "       CAST(strftime('%m', t.start_time) AS INTEGER) AS month, "
      "       CAST(strftime('%Y', t.start_time) AS INTEGER) AS year, "
      "       CAST(strftime('%H', t.start_time) AS INTEGER) AS hour, "
      "       CAST(strftime('%M', t.start_time) AS INTEGER) AS minute, "
      "       CAST(strftime('%S', t.start_time) AS INTEGER) AS second, "
      "       (julianday(t.end_time) - julianday(t.start_time)) AS duration_days "
      "FROM Project p "
      "INNER JOIN TimeLog t ON p.project_id = t.project_id");

  std::vector<TimeMetrics> result;
  result.reserve(64);

  // Execute and map rows into TimeMetrics via an intermediate RawRow
  stmt.execute([&](int project_id,
                   const std::string &name,
                   int day,
                   int month,
                   int year,
                   int hour,
                   int minute,
                   int second,
                   double duration_days) {
    TimeMetrics tm;
    tm.project_id = project_id;
    tm.name = name;
    tm.day = day;
    tm.month = month;
    tm.year = year;
    tm.hour = hour;
    tm.minute = minute;
    tm.second = second;
    tm.duration_days = duration_days;
    result.emplace_back(std::move(tm));
  });

  return result;
}

}  // namespace project_time_tracking
