```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <cmath>    // for std::round

namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen;

  // Open SQLite connection
  sqlite::connection db{"test_db.sqlite"};

  // Build and execute the query:
  // SELECT u.user_id, u.name,
  //        COUNT(p.post_id) AS post_count,
  //        AVG(length(p.content)) AS avg_length
  // FROM User u
  // LEFT JOIN Post p ON u.user_id = p.user_id
  // GROUP BY u.user_id, u.name;
  auto stmt = make_query(db)
      .select(
          column<User>(&User::user_id),
          column<User>(&User::name),
          count(column<Post>(&Post::post_id)),
          avg(sql("length(" + column_name<Post>(&Post::content) + ")")))
      .from<User>()
      .left_join<Post>(on(column<User>(&User::user_id) == column<Post>(&Post::user_id)))
      .group_by(
          column<User>(&User::user_id),
          column<User>(&User::name))
      .prepare();

  std::vector<Stats> results;

  // We expect 4 columns: user_id (int), name (string),
  // post_count (integer / 64-bit), avg_length (double or null).
  while (stmt.step()) {
    Stats s{};

    // Column 0: user_id
    s.user_id = stmt.get<int>(0);

    // Column 1: name
    s.name = stmt.get<std::string>(1);

    // Column 2: post_count (COUNT(...) is integral; fetch as 64-bit then narrow)
    auto cnt = stmt.get<std::int64_t>(2);
    s.post_count = static_cast<int>(cnt);

    // Column 3: avg_length (may be NULL if user has no posts)
    if (stmt.is_null(3)) {
      s.avg_length = std::nullopt;
    } else {
      double avg_len = stmt.get<double>(3);
      s.avg_length = avg_len;
    }

    results.emplace_back(std::move(s));
  }

  return results;
}

}  // namespace group_by_with_aggregations
